text:
{
  "formal_minutes": {
    "meeting_title": "UI 테마 패키지 릴리스 준비 점검",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "민준",
      "서연",
      "도윤",
      "하라"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
        "basis": "수요일 릴리스 제안에 대해 스모크 테스트 선행 필요 의견이 제기된 뒤 최종 정리됨."
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 한다.",
        "basis": "스크립트에서 불일치를 무시하자는 제안은 채택되지 않음."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일에 공개 릴리스한다.",
        "result": "반려",
        "reason": "스모크 테스트가 먼저 통과해야 한다는 이견이 받아들여짐."
      },
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경한다.",
        "result": "반려",
        "reason": "불일치 발생 시 먼저 패키지 설정을 점검하기로 결정함."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "확정된 공개 릴리스 결정이 아님."
      },
      {
        "goal": "README 설치 절차를 목요일까지 가능하면 검토",
        "status": "희망 일정",
        "note": "담당자 미지정, 확정 일정 아님."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "state": "필요성은 언급되었으나 담당자와 확정 일정이 정해지지 않음."
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음."
      },
      {
        "risk": "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자를 오도할 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "민준",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "도윤",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 검토한다.",
      "due": "목요일 가능 시",
      "status": "담당자 미지정",
      "source_certainty": "mentioned_not_confirmed"
    },
    {
      "owner": "하라",
      "task": "민준의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "선행 결과 대기",
      "source_certainty": "confirmed_partial_due_unspecified"
    }
  ],
  "followup_note": {
    "check_next": [
      "민준의 스모크 테스트 재실행 결과와 통과 여부를 확인한다.",
      "도윤의 실패 트리아지 노트 작성 완료 여부를 확인한다.",
      "스모크 결과 공유 후 하라의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토의 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자에 대한 답이 정해졌는지 확인한다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 포함할지 결정되었는지 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "지정되지 않은 추가 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 합성 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정 결정과 제안, 반려안, 내부 스트레치 목표를 혼동하지 않는다.",
    "담당자나 마감이 명시되지 않은 항목은 null 또는 미지정으로 유지한다.",
    "열린 질문은 답이 정해진 것처럼 쓰지 않는다.",
    "위험은 언급된 범위 내에서만 기록하고 원인이나 영향을 확장 추론하지 않는다."
  ]
}
